// ===== SOUND EFFECTS =====
let _audioCtx = null;
function _getAudioCtx() {
  if(!_audioCtx) _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  return _audioCtx;
}
function _playTone(freq, dur, type, vol) {
  try {
    var ctx = _getAudioCtx();
    var osc = ctx.createOscillator();
    var gain = ctx.createGain();
    osc.type = type || 'sine';
    osc.frequency.setValueAtTime(freq, ctx.currentTime);
    gain.gain.setValueAtTime(vol || 0.3, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + dur);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + dur);
  } catch(e) {}
}
function sfxClick() { _playTone(800, 0.06, 'sine', 0.2); setTimeout(function(){ _playTone(1200, 0.04, 'sine', 0.12); }, 30); }
function sfxSuccess() { _playTone(523, 0.1, 'sine', 0.18); setTimeout(function(){ _playTone(659, 0.1, 'sine', 0.18); }, 80); setTimeout(function(){ _playTone(784, 0.15, 'sine', 0.18); }, 160); }
function sfxError() { _playTone(300, 0.15, 'square', 0.12); setTimeout(function(){ _playTone(250, 0.2, 'square', 0.1); }, 100); }
function sfxCoin() { _playTone(988, 0.08, 'sine', 0.18); setTimeout(function(){ _playTone(1319, 0.12, 'sine', 0.22); }, 60); }

// ===== MATCH SOUND EFFECTS =====
let _matchNoiseNode = null;
let _matchNoiseGain = null;

function sfxCrowdStart() {
  try {
    var ctx = _getAudioCtx();
    var bufSize = ctx.sampleRate * 3;
    var buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
    var data = buf.getChannelData(0);
    for(var i = 0; i < bufSize; i++) { data[i] = (Math.random()*2-1) * 0.5; }
    _matchNoiseNode = ctx.createBufferSource();
    _matchNoiseNode.buffer = buf;
    _matchNoiseNode.loop = true;
    var filter = ctx.createBiquadFilter();
    filter.type = 'lowpass'; filter.frequency.value = 800; filter.Q.value = 0.5;
    _matchNoiseGain = ctx.createGain();
    _matchNoiseGain.gain.setValueAtTime(0, ctx.currentTime);
    _matchNoiseGain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + 1.5);
    _matchNoiseNode.connect(filter);
    filter.connect(_matchNoiseGain);
    _matchNoiseGain.connect(ctx.destination);
    _matchNoiseNode.start();
  } catch(e) {}
}
function sfxCrowdStop() {
  try {
    if(_matchNoiseGain) { var ctx = _getAudioCtx(); _matchNoiseGain.gain.linearRampToValueAtTime(0, ctx.currentTime + 2); }
    setTimeout(function() { try { if(_matchNoiseNode) _matchNoiseNode.stop(); } catch(e){} _matchNoiseNode = null; _matchNoiseGain = null; }, 2500);
  } catch(e) {}
}

// Match BGM - play external MP3
let _matchBGMAudio = null;
function sfxBGMStart() {
  try {
    if(_matchBGMAudio) { _matchBGMAudio.pause(); _matchBGMAudio = null; }
    _matchBGMAudio = new Audio("data:audio/ogg;base64,");
    _matchBGMAudio.loop = true;
    _matchBGMAudio.volume = 0;
    _matchBGMAudio.play().then(function() {
      var fade = setInterval(function() {
        if(!_matchBGMAudio || _matchBGMAudio.volume >= 0.35) { clearInterval(fade); return; }
        _matchBGMAudio.volume = Math.min(0.35, _matchBGMAudio.volume + 0.02);
      }, 100);
    }).catch(function(){});
  } catch(e) {}
}
function sfxBGMStop() {
  try {
    if(_matchBGMAudio) { _matchBGMAudio.pause(); }
    var fadeOut = setInterval(function() {
      if(!_matchBGMAudio) { clearInterval(fadeOut); return; }
      _matchBGMAudio.volume = Math.max(0, _matchBGMAudio.volume - 0.03);
      if(_matchBGMAudio.volume <= 0) { clearInterval(fadeOut); _matchBGMAudio.pause(); _matchBGMAudio.currentTime = 0; _matchBGMAudio = null; }
    }, 50);
    setTimeout(function() {
      if(_matchBGMAudio) { _matchBGMAudio.pause(); _matchBGMAudio.currentTime = 0; _matchBGMAudio = null; }
    }, 2000);
  } catch(e) {}
}

// Crowd GOAL cheer - much louder and longer
function sfxCrowdGoal() {
  try {
    var ctx = _getAudioCtx();
    // Boost crowd noise
    if(_matchNoiseGain) _matchNoiseGain.gain.linearRampToValueAtTime(0.45, ctx.currentTime + 0.15);
    // Triumphant fanfare: C5-E5-G5-C6 arpeggio
    var freqs = [523.25, 659.25, 783.99, 1046.5, 1318.5];
    var delays = [0, 100, 200, 320, 440];
    freqs.forEach(function(f, i) {
      setTimeout(function() {
        var osc = ctx.createOscillator(); osc.type = 'sine'; osc.frequency.value = f;
        var g = ctx.createGain();
        g.gain.setValueAtTime(0.35, ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.4);
        osc.connect(g); g.connect(ctx.destination);
        osc.start(); osc.stop(ctx.currentTime + 0.5);
      }, delays[i]);
    });
    // Hold crowd high for 2 seconds then fade
    setTimeout(function() { if(_matchNoiseGain) _matchNoiseGain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + 0.8); }, 2000);
  } catch(e) {}
}

// ===== PULSE WHISTLE (FC retro rhythm style) =====
// 快速脉冲方波，短促有力带节奏感

// 脉冲哨辅助函数：将一个哨声拆成多个短脉冲
function _pulseWhistle(freq, duration, vol, pulseCount) {
  try {
    var ctx = _getAudioCtx();
    var t = ctx.currentTime;
    pulseCount = pulseCount || 3;
    var pulseDur = duration / pulseCount;
    for(var i = 0; i < pulseCount; i++) {
      var pt = t + i * (pulseDur + 0.03);
      var o = ctx.createOscillator(); o.type = 'square'; o.frequency.value = freq + i * 50;
      var g = ctx.createGain();
      g.gain.setValueAtTime(0, pt);
      g.gain.linearRampToValueAtTime(vol, pt + 0.005);
      g.gain.linearRampToValueAtTime(0, pt + pulseDur);
      o.connect(g); g.connect(ctx.destination);
      o.start(pt); o.stop(pt + pulseDur + 0.02);
    }
  } catch(e) {}
}

// 长哨声（开赛/半场/终场）— 三组脉冲递进
function sfxWhistle() {
  _pulseWhistle(2800, 0.18, 0.16, 3);
  setTimeout(function(){ _pulseWhistle(3000, 0.15, 0.14, 3); }, 350);
  setTimeout(function(){ _pulseWhistle(3200, 0.12, 0.12, 2); }, 650);
}

// 犯规哨声 — 短促双脉冲
function sfxFoulWhistle() {
  _pulseWhistle(3000, 0.2, 0.16, 2);
}

// 红黄牌哨声
function sfxCard(isRed) {
  if(isRed) {
    // 红牌：两组急促脉冲
    _pulseWhistle(3200, 0.15, 0.16, 2);
    setTimeout(function(){ _pulseWhistle(3400, 0.18, 0.15, 3); }, 250);
  } else {
    // 黄牌：一组短脉冲
    _pulseWhistle(3000, 0.12, 0.14, 2);
  }
}

